import{_ as l,c as a,o as i,ae as r}from"./chunks/framework.CDjunVez.js";const h=JSON.parse('{"title":"Firewall","description":"","frontmatter":{},"headers":[],"relativePath":"features/firewall.md","filePath":"features/firewall.md"}'),t={name:"features/firewall.md"};function o(s,e,n,u,d,c){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="firewall" tabindex="-1">Firewall <a class="header-anchor" href="#firewall" aria-label="Permalink to &quot;Firewall&quot;">​</a></h1><h2 id="firewall-management" tabindex="-1">Firewall Management <a class="header-anchor" href="#firewall-management" aria-label="Permalink to &quot;Firewall Management&quot;">​</a></h2><p>KiwiPanel provides <strong>basic, transparent firewall setup</strong> to help secure your server without hiding or abstracting system behavior.</p><p>Firewall configuration is <strong>opt-in</strong>, <strong>non-destructive</strong>, and always uses <strong>native Linux firewall tools</strong>.</p><hr><h3 id="supported-firewalls" tabindex="-1">Supported Firewalls <a class="header-anchor" href="#supported-firewalls" aria-label="Permalink to &quot;Supported Firewalls&quot;">​</a></h3><p>KiwiPanel automatically detects the operating system family and uses the appropriate firewall:</p><ul><li><strong>Debian / Ubuntu</strong> → <code>ufw</code></li><li><strong>Rocky / Alma / RHEL</strong> → <code>firewalld</code></li></ul><p>No custom firewall layer is introduced.</p><hr><h3 id="design-principles" tabindex="-1">Design Principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to &quot;Design Principles&quot;">​</a></h3><p>KiwiPanel firewall handling follows these rules:</p><ul><li>Uses <strong>standard system tools only</strong></li><li>Makes <strong>explicit rule changes</strong></li><li>Does <strong>not overwrite existing rules silently</strong></li><li>Avoids background agents or custom daemons</li><li>Leaves the firewall <strong>fully manageable outside KiwiPanel</strong></li></ul><p>You can always inspect, modify, or disable the firewall manually.</p><hr><h3 id="default-behavior" tabindex="-1">Default Behavior <a class="header-anchor" href="#default-behavior" aria-label="Permalink to &quot;Default Behavior&quot;">​</a></h3><p>When firewall setup is enabled, KiwiPanel:</p><ul><li>Enables the system firewall if not already active</li><li>Allows <strong>SSH access</strong> (port 22 by default)</li><li>Allows <strong>HTTP / HTTPS</strong> traffic: <ul><li>Port <code>80</code> (HTTP)</li><li>Port <code>443</code> (HTTPS)</li></ul></li><li>Allows <strong>KiwiPanel access</strong>: <ul><li>Port <code>8443</code></li></ul></li><li>Denies all other incoming traffic by default</li></ul><p>No outbound traffic is restricted.</p><hr><h3 id="cloud-provider-notice" tabindex="-1">Cloud Provider Notice <a class="header-anchor" href="#cloud-provider-notice" aria-label="Permalink to &quot;Cloud Provider Notice&quot;">​</a></h3><p>Some cloud providers require ports to be opened <strong>outside the server</strong>, for example:</p><ul><li>Amazon Lightsail</li><li>Oracle Cloud</li><li>Other managed VPS platforms</li></ul><p>Even if the firewall allows a port, traffic may still be blocked at the provider level.</p><hr><h3 id="non-goals" tabindex="-1">Non-Goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-Goals&quot;">​</a></h3><p>KiwiPanel <strong>does not</strong>:</p><ul><li>Implement its own firewall engine</li><li>Automatically close ports without user awareness</li><li>Modify existing complex firewall rules</li><li>Attempt to manage advanced firewall scenarios (VPNs, custom routing)</li></ul><p>Advanced setups are intentionally left to the administrator.</p><hr><h3 id="visibility-control" tabindex="-1">Visibility &amp; Control <a class="header-anchor" href="#visibility-control" aria-label="Permalink to &quot;Visibility &amp; Control&quot;">​</a></h3><p>All firewall actions performed by KiwiPanel:</p><ul><li>Are logged</li><li>Can be reviewed</li><li>Can be reverted manually</li><li>Do not prevent direct usage of <code>ufw</code> or <code>firewall-cmd</code></li></ul><p>KiwiPanel assists with <strong>safe defaults</strong>, not enforcement.</p><hr><h3 id="future-plans" tabindex="-1">Future Plans <a class="header-anchor" href="#future-plans" aria-label="Permalink to &quot;Future Plans&quot;">​</a></h3><p>Planned improvements include:</p><ul><li>Firewall status overview in the Web UI</li><li>Explicit port visibility per service</li><li>Warnings for exposed or unsafe ports</li><li>Integration with security audit checks</li><li>Optional Fail2ban / CrowdSec coordination</li></ul><hr><h3 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>KiwiPanel treats the firewall as a <strong>first-class system component</strong>, not a black box.</p><p>The goal is simple:</p><blockquote><p>Secure the server by default, without taking control away from the user.</p></blockquote>',43)])])}const f=l(t,[["render",o]]);export{h as __pageData,f as default};
